sql:
SELECT SUM(points_earned) AS total_points
FROM driver_performance
WHERE event_id = 0;

external_knowledge:
; The "top three trucks" refers to the trucks with the highest average distance traveled in each event, as calculated by the query; 
; The "event information" includes the event name and date; 
; The "truck details" include the truck name and model; 
; The "driver information" includes the driver name.

sql:
SELECT COUNT(DISTINCT e.event_id) AS total_events, COUNT(DISTINCT ep.driver_id) AS total_unique_drivers
FROM events e
JOIN event_participants ep ON e.event_id = ep.event_id;
